mapper.update:
UPDATE holdings
SET krw_cost_basis = krw_cost_basis * (quantity - #{qty}) / quantity,
    quantity       = quantity - #{qty}
WHERE account_id = #{accountId} AND stock_code = #{stockCode}
  AND quantity - fractional_qty - held_whole - #{qty} >= 0

UPDATE holdings
SET held_whole = held_whole + #{qty}
WHERE account_id = #{accountId} AND stock_code = #{stockCode}
  AND quantity - fractional_qty - held_whole - #{qty} >= 0

UPDATE holdings
SET held_whole = held_whole - #{qty}
WHERE account_id = #{accountId} AND stock_code = #{stockCode}
  AND held_whole >= #{qty}

mapper.select:
SELECT quantity - fractional_qty - held_whole
FROM holdings
WHERE account_id = #{accountId} AND stock_code = #{stockCode}

SELECT fractional_qty - held_fractional
FROM holdings
WHERE account_id = #{accountId} AND stock_code = #{stockCode}

mapper.update:
UPDATE holdings
SET held_fractional = held_fractional + #{qty}
WHERE account_id = #{accountId} AND stock_code = #{stockCode}
  AND fractional_qty - held_fractional - #{qty} >= 0

UPDATE holdings
SET held_fractional = held_fractional - #{qty}
WHERE account_id = #{accountId} AND stock_code = #{stockCode}
  AND held_fractional >= #{qty}

UPDATE holdings
SET krw_cost_basis = krw_cost_basis * (quantity - #{qty}) / quantity,
    quantity       = quantity - #{qty},
    fractional_qty = fractional_qty - #{qty}
WHERE account_id = #{accountId} AND stock_code = #{stockCode}
  AND fractional_qty - #{qty} >= 0

UPDATE holdings
SET fractional_qty = fractional_qty - #{wholeQty}
WHERE account_id = #{accountId} AND stock_code = #{stockCode}
  AND fractional_qty - held_fractional - #{wholeQty} >= 0
